#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=5e5+10;
struct XXJ
{
	int P[20];inline void clear(){memset(P,0,sizeof(P));}
	inline void ins(int x){drep(19,0,i)if(x>>i){if(!P[i]){P[i]=x;return;}x^=P[i];}}
	inline XXJ friend operator + (XXJ x,XXJ y){drep(19,0,i)if(y.P[i])x.ins(y.P[i]);return x;}
}s[N];
vector<int> Q[N<<2];int n,a[N],m,ql[N],qr[N],ans[N];
inline void add(int ql,int qr,int w,int l=1,int r=n,int cur=1)
{
	if(l==r){Q[cur].push_back(w);return;}
	int mid=(l+r)>>1;if(ql<=mid&&qr>mid){Q[cur].push_back(w);return;}
	(qr<=mid)?add(ql,qr,w,l,mid,cur<<1):add(ql,qr,w,mid+1,r,cur<<1|1);
}
inline void Solve(int l=1,int r=n,int cur=1)
{
	if(l==r){for(int v:Q[cur])ans[v]=a[l];return;}int mid=(l+r)>>1;
	s[mid].clear();s[mid].ins(a[mid]);s[mid+1].clear();s[mid+1].ins(a[mid+1]);
	drep(mid-1,l,i)s[i]=s[i+1],s[i].ins(a[i]);
	rep(mid+2,r,i)s[i]=s[i-1],s[i].ins(a[i]);
	for(int v:Q[cur])
	{
		XXJ A=s[ql[v]]+s[qr[v]];int res=0;
		drep(19,0,i)if((A.P[i]^res)>res)res^=A.P[i];ans[v]=res; 
	}
	Solve(l,mid,cur<<1);Solve(mid+1,r,cur<<1|1);
}
int main()
{
	n=read();rep(1,n,i)a[i]=read();
	m=read();rep(1,m,i)ql[i]=read(),qr[i]=read(),add(ql[i],qr[i],i);
	Solve();rep(1,m,i)printf("%d\n",ans[i]);
}
